function init$FlowMulti$GridQuery$&Identity;(g) {
  var f = g._$parentForm, c = String.fromCharCode(253), a = f._$queryFilterString.split(c);
  g._alterTitle = [null, [['%d1', formatDateView(a[2]), true], ['%d2', formatDateView(a[3]), true]]];
}

function load$FlowMulti$GridQuery$&Identity;(g) {
  g._$k = [];
  g._$f = ['stt_rec', 'stt_rec0'];
  g._$i = [g._getColumnOrder('stt_rec'), g._getColumnOrder('stt_rec0')];
  g._$s = [g._getColumnOrder('so_chuyen'), g._getColumnOrder('loai_vc'), g._getColumnOrder('ten_loai%l')];
  g.add_onResponseComplete(on$FlowMulti$GridQuery$&Identity;ResponseComplete);
}
function dispose$FlowMulti$GridQuery$&Identity;(g) {
  g._$k = g._$f = g._$i = g._$s = null;
  try {g.remove_onResponseComplete(on$FlowMulti$GridQuery$&Identity;ResponseComplete);} catch (ex) {}
}
function scatter$FlowMulti$GridQuery$&Identity;(g) {scatter$FlowMulti$GridQuery(g);}

function onChange$FlowMulti$GridQuery$&Identity;InvoiceQuantity(o) {
  var g = o.grid, a = o.id.split('_inputCell_'), r = a[1].split('.')[0];
  var l = g._getColumnOrder('loai_vc'), v = g._getItemValue(r, l);
  if (v != '' || o.value != 0) addTagRow$FlowMulti$(g, r);
  else removeTagRow$FlowMulti$(g, r);
}

function onChange$FlowMulti$GridQuery$&Identity;TransportType(o) {
  var g = o.grid, a = o.id.split('_inputCell_'), r = a[1].split('.')[0];
  var l = g._getColumnOrder('so_chuyen'), v = g._getItemValue(r, l);
  if (v != 0 || o.value != '') addTagRow$FlowMulti$(g, r);
  else removeTagRow$FlowMulti$(g, r);
  if (o.value != '') {
    g.request(o, 'TransportType', 'TransportType', ['loai_vc', ['r', 'Decimal', r]], null, true);
  }
}

function on$FlowMulti$GridQuery$&Identity;ResponseComplete(sender, e) {
  var g = e.object, context = e.type.Context, result = e.type.Result, o = e.type.Object, f = g.get_element().parentForm;
  switch (context) {
    case 'TransportType':
    var r = result[1].Value;
    if (result[0].Value != '') {
      g._getItem(r, g._getColumnOrder('ten_loai%l')).value = result[0].Value;
      addTagRow$FlowMulti$(g, r);
    }
    else {
      var l = g._getColumnOrder('so_chuyen'), v = g._getItemValue(r, l);
      var c2 = g._getColumnOrder('loai_vc'), v2 = g._getItemValue(r, c2);
      g._getItem(r, g._getColumnOrder('ten_loai%l')).value = '';
      if (v != 0 || v2 != '') addTagRow$FlowMulti$(g, r);
      else removeTagRow$FlowMulti$(g, r);
    }
    break;s
    default:
      break;
  }
}








